<h3>MINI widget with click and receive link to calculator</h3>

```javascript
  <!doctype html>
  <html class="no-js" lang="pl">
    <head>
      <meta charset="utf-8">
      <meta name="viewport" content="width=device-width, initial-scale=1">
      <title>Widget mini with calculator link</title>
      <meta name="theme-color" content="#fafafa">
      <style>
        .button {
          margin: 0;
          padding: 0;
          border: 0;
          background: 0;
          cursor: pointer;
        }
        /* The Modal (background) */
        .calculator-modal-custom {
          display: none;
          position: fixed;
          z-index: 1;
          left: 0;
          top: 0;
          width: 100%;
          height: 100%;
          overflow: auto;
          background-color: rgba(0,0,0,0.4);
        }

        /* Modal Content */
        .calculator-modal-custom__content {
          background: none;
          margin: auto;
          width: 100%;
          height: 100vh;
          display: flex;
          transform: translate(-50%, -50%);
          left: 50%;
          top: 50%;
          position: fixed;
        }
      </style>
    </head>
    <body>
      <!-- Custom button -->
      <button class="button" id="calculator-btn-custom"></button>
      <!-- Container for calling your own calculator modal -->
      <div id="calculator-modal-custom" class="calculator-modal-custom">
        <div class="calculator-modal-custom__content">
          <iframe
            id="calculator-modal-custom-iframe"
            style="border: none; margin: 0; padding: 0; width: 100%; height: 100%;"
            title="installment-calculator"></iframe>
        </div>
      </div>
      <!-- Embedding tag with package -->
      <script type="application/javascript" src="https://apm.przelewy24.pl/installments/installment-calculator-app.umd.sdk.js"></script>
      <script>
        document.addEventListener("DOMContentLoaded", async () => {
          const config = {
            sign: "string",
            posid: 'test', // Payment point identifier posId.
            method: '303',
            amount: 1000, // grosze
            currency: "PLN", // Currency only "PLN"
            lang: "pl",  // For now only pl
            test: false  // Optionally, for use during testing, takes a boolean value
          }
          // Create constructor and provide config
          const installmentCalculatorApp = new InstallmentCalculatorApp(config);
          // Creating a mini Widget component
          const miniWidget = await installmentCalculatorApp.create('mini-widget');
          // Render the miniWidget component in the tag with id calculator-btn-custom
          miniWidget.render('calculator-btn-custom');

          // CUSTOM
          const modal = document.getElementById('calculator-modal-custom');
          const button = document.getElementById('calculator-btn-custom');
          const iframe = document.getElementById('calculator-modal-custom-iframe');
          button.onclick = function () {
            modal.style.display = "block";
            const customLink = installmentCalculatorApp.getCalculatorUrl();
            if (!iframe.src) {
              iframe.src = customLink;
            }
          };

          const handleMessage = (event) => {
            if (event.data?.type === 'READY') {
              iframe.contentWindow.postMessage({ config }, '*');
            }
            if (event.data.action === 'closeModal') {
              modal.style.display = 'none';
            }
          };

          window.addEventListener('message', handleMessage);
        });
      </script>
    </body>
  </html>
```
